select

from test_sample
where id = #{id,jdbcType=INTEGER}

SELECT t1.id as id, t1.task_id AS taskId, t1.sample_id as sampleId, t2.check_item_id AS checkItemId, t1.check_item_name AS checkItemName, t1.times AS times, t1.unit_price AS checkPrice, t1.standard_id AS standardId, CONCAT(t3.CODE,'《',t3.NAME,'》') As standardName, t1.method_id AS methodId, t4.name AS methodName, IFNULL(t5.name,"——") as testingRoom, t2.check_item_pid as checkItemPid FROM test_entrusted_sample_checkitem_rel AS t1 LEFT JOIN test_product_item AS t2 ON t1.check_item_id = t2.check_item_id LEFT JOIN test_standard_file AS t3 ON t1.standard_id = t3.id LEFT JOIN test_method As t4 ON t4.id = t1.method_id LEFT JOIN test_team as t5 ON t5.id = t1.dept_id
and t1.sample_id = #{sampleId}
and t1.entrust_id = #{entrustmentId}

SELECT t1.id as id, t1.sample_id as sampleId, t2.check_item_id AS checkItemId, t1.check_item_name AS checkItemName, t1.times AS times, t1.unit_price AS checkPrice, t1.standard_id AS standardId, CONCAT(t3.CODE,'《',t3.NAME,'》') As standardName, t1.method_id AS methodId, t4.name AS methodName, t5.name as testingRoom, t2.check_item_pid as checkItemPid FROM test_entrusted_sample_checkitem_rel AS t1 LEFT JOIN test_product_item AS t2 ON t1.check_item_id = t2.check_item_id LEFT JOIN (select * from test_standard_file union all select * from test_standard_file_record) AS t3 ON t1.standard_id = t3.id LEFT JOIN test_method As t4 ON t4.id = t1.method_id LEFT JOIN test_team as t5 ON t5.id = t1.dept_id
and dept_id is null
and t1.sample_id = #{sampleId}
and t1.entrust_id = #{entrustmentId}

SELECT t1.check_item_id AS checkItemId, t2.check_item_name AS checkItemName, t1.method_id AS methodId FROM test_entrusted_sample_checkitem_rel AS t1 LEFT JOIN test_product_item AS t2 ON t1.check_item_id = t2.check_item_id
and t1.sample_id = #{sampleId}
and t1.entrust_id = #{entrustmentId}

SELECT t1.id id, t1.company_id companyId, t2.company_name companyName, t1.product_id productId, t1.sample_name sampleName, t1.sample_code sampleCode, t1.specs specs, t1.batch_number batchNumber, t1.manufacturer manufacturer, t1.sample_origin sampleOrigin, t1.outward outward, t1.picture picture, t1.save_place savePlace, t1.admin admin, t1.sample_groups sampleGroups, t1.quantity_per_group quantityPerGroup, t1.inspector inspector, t1.received_date receivedDate, t1.sample_requirement sampleRequirement, t1.generation generation, t1.state state, t1.check_date checkDate, t1.remark remark, t1.insert_flag insertFlag FROM test_sample t1 LEFT JOIN test_company t2 ON t1.company_id = t2.company_id
and product_id = #{productId}
and manufacturer LIKE CONCAT('%',#{manufacturer},'%')
and batch_number LIKE CONCAT('%',#{batchNumber},'%')
and received_date=#{receivedDate}
and state=#{state}
and company_id=#{companyId}
and insert_flag=#{insertFlag}

