SELECT DISTINCT t1.standard_id
FROM test_entrusted_sample_standard_rel as t1
         LEFT JOIN (select * from test_standard_file union all select * from  test_standard_file_record) as t2 ON t1.standard_id = t2.id
WHERE t1.sample_id = #{sampleId}
  and t1.entrustment_id = #{entrustmentId}

SELECT DISTINCT t1.standard_id                     as standardId,
                CONCAT(t2.name, '《', t2.code, '》') as standardName
FROM test_entrusted_sample_standard_rel as t1
         LEFT JOIN test_standard_file as t2 ON t1.standard_id = t2.id
WHERE t1.sample_id = #{sampleId}
  and t1.entrustment_id = #{entrustmentId}

SELECT t1.company_id, t1.company_name, t1.sample_name, t1.specs, t1.manufacturer, t1.sample_origin, t1.outward, t1.sample_groups, t1.quantity_per_group, t1.inspector, t1.received_date, t1.sample_requirement, t1.generation, t1.product_id, t1.insert_flag, t2.id, t2.sample_code, t2.batch_number, t2.picture FROM ( SELECT DISTINCT t1.company_id, t2.company_name, sample_name, specs, manufacturer, sample_origin, outward, sample_groups, quantity_per_group, inspector, received_date, sample_requirement, generation, product_id, insert_flag FROM test_sample t1 LEFT JOIN test_company t2 ON t1.company_id = t2.company_id ) t1 LEFT JOIN ( SELECT id, sample_code, batch_number, picture, insert_flag FROM test_sample ) t2 ON t1.insert_flag = t2.insert_flag
and product_id = #{productId}
and manufacturer LIKE CONCAT('%',#{manufacturer},'%')
and sample_origin LIKE CONCAT('%',#{sampleOrigin},'%')
and batch_number LIKE CONCAT('%',#{batchNumber},'%')
and state=#{state}
and company_id=#{companyId}
and str_to_date( t1.received_date, '%Y-%m-%d' ) >= str_to_date( #{beginDate}, '%Y-%m-%d' )
and str_to_date( t1.received_date, '%Y-%m-%d' ) <= str_to_date( #{endDate}, '%Y-%m-%d' )
ORDER BY t1.insert_flag desc

SELECT t1.company_id, t1.company_name, t1.sample_name, t1.specs, t1.manufacturer, t1.sample_origin, t1.outward, t1.sample_groups, t1.quantity_per_group, t1.inspector, t1.received_date, t1.sample_requirement, t1.generation, t1.product_id, t1.insert_flag, t1.sample_quantity, t1.alias_name FROM ( SELECT DISTINCT t1.company_id, t2.company_name, sample_name, specs, manufacturer, sample_origin, outward, sample_groups, quantity_per_group, inspector, received_date, sample_requirement, generation, product_id, insert_flag, t1.sample_quantity, t1.alias_name FROM test_sample t1 LEFT JOIN test_company t2 ON t1.company_id = t2.company_id ) t1
and product_id = #{productId}
and manufacturer LIKE CONCAT('%',#{manufacturer},'%')
and sample_origin LIKE CONCAT('%',#{sampleOrigin},'%')
and batch_number LIKE CONCAT('%',#{batchNumber},'%')
and state=#{state}
and company_id=#{companyId}
and str_to_date( t1.received_date, '%Y-%m-%d' ) >= str_to_date( #{beginDate}, '%Y-%m-%d' )
and str_to_date( t1.received_date, '%Y-%m-%d' ) <= str_to_date( #{endDate}, '%Y-%m-%d' )
ORDER BY t1.insert_flag desc

